x_snc_airop_check_definition.check_script:
(function() {
    try {
        if (!gs.tableExists("sn_hr_core_coe")) {
            return { status: "not_applicable", actualValue: "HR COE table not found", finding: "HR Centers of Excellence table does not exist on this instance." };
        }
        var ga = new GlideAggregate("sn_hr_core_coe");
        ga.addQuery("active", true);
        ga.addAggregate("COUNT");
        ga.query();
        var count = ga.next() ? parseInt(ga.getAggregate("COUNT")) : 0;
        var actualValue = count + " active HR Centers of Excellence";
        if (count >= 3) {
            return { status: "ready", actualValue: actualValue, finding: count + " active HR COEs. Now Assist HRSD can provide department-aware AI case routing based on COE structure." };
        } else if (count >= 1) {
            return { status: "needs_attention", actualValue: actualValue, finding: "Only " + count + " active HR COE(s) (target: 3+). Now Assist HRSD routing will have limited organizational differentiation." };
        } else {
            return { status: "not_ready", actualValue: actualValue, finding: "No active HR COEs configured. COEs define the routing structure Now Assist uses for intelligent HR case assignment." };
        }
    } catch(e) {
        return { status: "needs_validation", actualValue: "Check failed", finding: "Script execution error: " + e.message };
    }
})
